declare i64 @strtol(ptr, ptr, i32)

define i64 @strtol_not_const_str(ptr %s) {
  %call = call i64 @strtol(ptr %s, ptr null, i32 10)
  ret i64 %call
}

declare i32 @atoi(ptr)

define i32 @atoi_not_const_str(ptr %s) {
  %call = call i32 @atoi(ptr %s)
  ret i32 %call
}

declare i32 @strtol(ptr, ptr, i32)

define i32 @strtol_not_const_str(ptr %s) {
  %call = call i32 @strtol(ptr %s, ptr null, i32 10)
  ret i32 %call
}

@.str.6 = external hidden unnamed_addr constant [10 x i8], align 1

declare i32 @atol(ptr)

define i32 @atol_test() {
  %call = call i32 @atol(ptr @.str.6)
  ret i32 %call
}

declare i32 @atoi(ptr)

define i32 @atoi_not_const_str(ptr %s) {
  %call = call i32 @atoi(ptr %s)
  ret i32 %call
}

@.str.5 = external hidden unnamed_addr constant [11 x i8], align 1

declare i32 @atoll(ptr)

define i32 @atoll_test() {
  %call = call i32 @atoll(ptr @.str.5)
  ret i32 %call
}

@a5 = external constant [5 x i8]

declare i32 @atoi(ptr)

define i32 @fold_atoi_past_end() {
  %p5 = getelementptr [5 x i8], ptr @a5, i32 0, i32 5
  %i = call i32 @atoi(ptr %p5)
  ret i32 %i
}
